  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  input,
  output,
} from '@angular/core';

@Component({
  selector: 'smart-ngx-smart-components',
  imports: [],
  template: `<p>NgxSmartComponents works!</p>`,
  styles: `
    :host {
      display: block;
    }
  `,
  encapsulation: ViewEncapsulation.Emulated,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NgxSmartComponents {
  /** A sample string input for demonstration purposes. */
  readonly sampleInput = input<string>();

  /** A sample event output emitted when an action occurs. */
  readonly sampleOutput = output<string>();
}

